{"folder": ".", "file": "todo_manager.py", "content": "#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
简单的命令行待办事项管理器
作者: ClawTest
为: Sam
"""

import json
import os
from datetime import datetime

class TodoManager:
    def __init__(self, filename="todos.json"):
        self.filename = filename
        self.todos = self.load_todos()

    def load_todos(self):
        if os.path.exists(self.filename):
            with open(self.filename, 'r', encoding='utf-8') as f:
                return json.load(f)
        return []

    def save_todos(self):
        with open(self.filename, 'w', encoding='utf-8') as f:
            json.dump(self.todos, f, ensure_ascii=False, indent=2)

    def add_todo(self, task, priority="medium"):
        todo = {
            "id": len(self.todos) + 1,
            "task": task,
            "priority": priority,
            "completed": False,
            "created_at": datetime.now().strftime("%Y-%m-%d %H:%M:%S")
        }
        self.todos.append(todo)
        self.save_todos()
        print(f"✅ 已添加任务: {task}")
        return todo

    def list_todos(self):
        if not self.todos:
            print("📭 暂无待办事项")
            return

        print("\n" + "="*60)
        print(f"{'ID':<4} {'任务':<30} {'优先级':<8} {'状态':<8}")
        print("="*60)

        for todo in self.todos:
            status = "✓ 已完成" if todo["completed"] else "○ 未完成"
            priority = todo["priority"].upper()
            print(f"{todo['id']:<4} {todo['task']:<30} {priority:<8} {status:<8}")

        print("="*60 + "\n")

    def complete_todo(self, todo_id):
        for todo in self.todos:
            if todo["id"] == todo_id:
                todo["completed"] = True
                self.save_todos()
                print(f"✅ 任务已完成: {todo['task']}")
                return
        print(f"❌ 未找到 ID 为 {todo_id} 的任务")

    def delete_todo(self, todo_id):
        for i, todo in enumerate(self.todos):
            if todo["id"] == todo_id:
                removed = self.todos.pop(i)
                self.save_todos()
                print(f"🗑️ 已删除任务: {removed['task']}")
                return
        print(f"❌ 未找到 ID 为 {todo_id} 的任务")

    def stats(self):
        total = len(self.todos)
        completed = sum(1 for t in self.todos if t["completed"])
        pending = total - completed

        print("\n📊 待办事项统计:")
        print(f"   总任务数: {total}")
        print(f"   已完成: {completed}")
        print(f"   待完成: {pending}")
        if total > 0:
            rate = (completed / total) * 100
            print(f"   完成率: {rate:.1f}%")
        print()

def main():
    manager = TodoManager()

    print("\n" + "="*50)
    print("📝 欢迎使用待办事项管理器")
    print("="*50)
    print("可用命令:")
    print("  add <任务> [优先级]  - 添加任务 (优先级: high/medium/low)")
    print("  list                - 查看所有任务")
    print("  complete <ID>       - 标记任务完成")
    print("  delete <ID>         - 删除任务")
    print("  stats               - 查看统计信息")
    print("  quit                - 退出程序")
    print("="*50 + "\n")

    while True:
        try:
            command = input(">>> ").strip().lower()

            if not command:
                continue

            parts = command.split(maxsplit=2)
            cmd = parts[0]

            if cmd == "quit" or cmd == "exit":
                print("👋 再见！")
                break

            elif cmd == "add":
                if len(parts) < 2:
                    print("❌ 用法: add <任务> [优先级]")
                else:
                    task = parts[1]
                    priority = parts[2] if len(parts) > 2 else "medium"
                    manager.add_todo(task, priority)

            elif cmd == "list":
                manager.list_todos()

            elif cmd == "complete":
                if len(parts) < 2:
                    print("❌ 用法: complete <ID>")
                else:
                    try:
                        manager.complete_todo(int(parts[1]))
                    except ValueError:
                        print("❌ ID 必须是数字")

            elif cmd == "delete":
                if len(parts) < 2:
                    print("❌ 用法: delete <ID>")
                else:
                    try:
                        manager.delete_todo(int(parts[1]))
                    except ValueError:
                        print("❌ ID 必须是数字")

            elif cmd == "stats":
                manager.stats()

            else:
                print(f"❌ 未知命令: {cmd}")
                print("   输入 'help' 查看可用命令")

        except KeyboardInterrupt:
            print("\n👋 再见！")
            break
        except Exception as e:
            print(f"❌ 发生错误: {e}")

if __name__ == "__main__":
    main()
"}

